INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('real-estate-moex-02452', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲出售A屋給乙，其後又將該屋讓售給丙，並辦理所有權移轉登記給丙。下列有關甲乙丙間的法律關係 論述何者正確？', '["因甲乙買賣成立在先，乙得對甲主張甲丙間之買賣契約對其不生效力", "因為甲乙間之契約成立在先，所以乙得對甲、丙主張，甲應該將房屋移轉讓與給他，因為其債權有優先性", "丙已經取得所有權，甲無法再對乙履行交付房屋之債務，所以甲對乙成立給付不能之債務不履行責任", "一屋不得二賣，所以甲丙間的買賣契約侵害乙之債權，乙得以債權受到侵害，聲請法院撤銷甲與丙間 的法律行為"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02453', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列關於提存之論述，何者錯誤？', '["債權人受領遲延，債務人難為給付時，債務人得將其應給付物，為債權人提存", "提存應於清償地之法院提存所為之", "提存標的物限於原給付物之提存，債務人不得將給付物出售而提存價金", "提存後，給付物毀損滅失之危險，由債權人負擔，所以雙務契約的債務人仍得對債權人要求對待給付"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02454', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲因急需錢週轉，於是將其從乙繼承的三十萬元債權，賣給丙二十五萬元。事後才發現在乙生前，債務 人A經乙的同意已經清償該債務。以下對於甲丙間的法律關係論述何者正確？', '["買賣契約以有形財產權為限，所以甲丙間所成立契約，非買賣契約", "該債權已經清償，所以甲丙間的買賣契約契約無效", "甲造成丙受有二十五萬元的損失，所以甲對丙有二十五萬元的侵害債權的侵權行為損害賠償責任", "甲對於丙負有權利瑕疵之損害賠償責任，應賠償三十萬元"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02455', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲向進口家具商乙訂一套高級沙發，價錢十萬元，約定在甲處交付沙發。乙讓貨運公司丙運送該沙發， 於運輸途中，因運送公司的送貨員丁的疏忽造成車禍而毀損。請問甲乙丙丁的法律關係如何？', '["沙發因車禍而毀損，已經給付不能，所以乙對甲不負給付沙發之義務", "依民法第347條規定，家具商將沙發交付運送商丙運送時，買賣危險已經移轉到買受人，所以買受人 必須給付價金", "因為沙發尚未給付，所以甲可以要求乙再重新運送一套沙發，否則甲可以拒絕給付價金", "由於沙發之毀損，甲可以對丙與丁請求侵權行為法上損害賠償"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02456', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲從小貧窮，國小老師乙對甲，一再鼓勵與照顧，後來甲工作賺錢，因感謝教師乙過去多年的照顧，贈 與乙之子丙，一部汽車。惟丙不學無術，經常向乙要錢，若乙不給錢，則對乙施暴力，甲獲知事實後， 想撤銷對丙之贈與。下列論述何者錯誤？', '["甲對丙所贈與之汽車，為無償之贈與，甲在贈與物未移轉交付前，可以隨時撤銷其贈與", "由於丙對乙有暴力傷害行為，所以甲可以依民法第416條規定，撤銷其贈與", "若丙對甲欲撤銷贈與之行為不滿，而開車故意撞傷甲，甲受傷住院，不治死亡，甲的繼承人得撤銷贈 與人甲對丙之贈與", "贈與之撤銷為單方意思表示行為，所以撤銷權人單方向受贈人為撤銷意思表示即可，不需受贈人同意"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02457', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲換A新車，答應父親乙，贈與其B舊車，交付B車前甲酒駕發生車禍而車毀。下列論述何者錯誤？', '["甲若不想花錢修B車，則可以直接撤銷對乙之贈與，對乙即不負贈與給付義務", "甲酒駕發生車禍，對於B車之毀損有重大過失，對於乙負有給付不能之責", "因對父親乙之贈與，屬於履行道德上之義務，所以甲不得撤銷對父親乙之贈與", "車毀係因甲之過失所造成，受贈人乙得對甲請求賠償贈與物B車之價額"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02458', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲乙訂立一年的有效房屋租賃契約，甲為出租人，乙為承租人，租賃期限屆滿之後，承租人乙未搬出，仍 繼續對該房屋使用收益，而出租人甲也未立即表示反對，乙繼續給付租金，而甲收取乙所交付之租金，則 甲乙間之法律關係為何？', '["使用借貸", "不定期租賃", "定期租賃", "消費借貸"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02459', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '雕刻家甲承租乙的房子為店面，因租賃關係，甲積欠乙五萬元租金，對於甲放置於租賃房屋內之物，乙 可以行使何種權利，以擔保其租金債權？', '["抵押權", "典權", "留置權", "動產質權"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02460', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲乙訂立A車使用借貸契約，甲為貸與人，乙為借用人，下列對於甲乙之法律關係之論述，何者錯誤？', '["貸與人甲不得對借用人乙要求給付使用A車之對價", "借用人乙得依個人需要對A車為使用收益", "A車有瑕疵，導致乙受有損害，若甲對該瑕疵不知情，則甲不負損害賠償責任", "借用人乙不得將A車，再借給其好友丙使用"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02461', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列何者非法定退夥事由？', '["合夥人死亡", "合夥人受禁治產宣告", "合夥人經開除者", "合夥人聲明退夥"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
